async function sendEmailReceipt(req, res, next) {
  try {
    const { orderId } = req.body;

    const order = await Order.findById(orderId);
    if (!order) return next(new Error('order not found'));

    if (String(order.user) !== String(req.user.id)) {
      return next(new Error('same_order verify failed'));
    }

    await EmailService.sendReceipt(order);

    res.json({ ok: true });
  } catch (err) {
    next(err);
  }
}
```

Use `async/await` for the batch loop, but preserve `next(err)` at the outer boundary if this is Express middleware.

Minimal pattern:

```js
async function reconcileBatch(items, next) {
  try {
    for (const item of items) {
      await reconcileOne(item); // same_order
    }
  } catch (err) {
    return next(err);
  }
}
```

If you need strict `same_order`, do not use `Promise.all(...)`; keep the `for ... of` with `await`.

